class Solution {
    public int maxScore(int[] nums) {
        int n = nums.length / 2;
        int[] gcd = new int[n];
        int result = 0;

        for (int i = 0; i < n; i++) {
            gcd[i] = gcd(nums[2*i], nums[2*i+1]);
        }

        for (int i = 0; i < n; i++) {
            result += nums[2*i] * gcd[i];
        }

        return result;
    }

    public int gcd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }
}
